import pandas as pd
from sklearn.model_selection import train_test_split
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
from sklearn.pipeline import Pipeline
from flask import Flask, request, jsonify

# --- Model Training ---

# Sample data (replace with your actual dataset)
data = {
    'text': [
        "Congratulations! You've won a free iPhone. Click here now!",
        "Meeting reminder: Project update at 3 PM today.",
        "URGENT: Your account has been compromised. Verify your details immediately.",
        "Hello, just following up on our last conversation.",
        "Claim your prize! Limited time offer. Don't miss out!",
        "Can you please send me the report by end of day?",
        "Viagra for sale! Best prices guaranteed.",
        "Regarding the document you requested.",
        "Get rich quick scheme! Invest now!",
        "Lunch plans for tomorrow?",
        "You've been selected for a special offer!",
        "Here's the agenda for the upcoming meeting.",
        "Free money no strings attached! Click here!",
        "Please review the attached file.",
        "Unlock exclusive discounts today!",
        "Your order has been shipped.",
        "Win a luxury vacation! Enter now!",
        "Confirming our appointment for next week.",
        "Make money from home! Easy steps!",
        "Just wanted to check in."
    ],
    'label': [
        1,  # Spam
        0,  # Ham
        1,  # Spam
        0,  # Ham
        1,  # Spam
        0,  # Ham
        1,  # Spam
        0,  # Ham
        1,  # Spam
        0,  # Ham
        1,  # Spam
        0,  # Ham
        1,  # Spam
        0,  # Ham
        1,  # Spam
        0,  # Ham
        1,  # Spam
        0,  # Ham
        1,  # Spam
        0   # Ham
    ]
}

df = pd.DataFrame(data)

# Split data
X_train, X_test, y_train, y_test = train_test_split(df['text'], df['label'], test_size=0.2, random_state=42)

# Create a pipeline: Vectorizer -> Logistic Regression
model_pipeline = Pipeline([
    ('vectorizer', CountVectorizer()),
    ('classifier', LogisticRegression(solver='liblinear'))
])

# Train the model
model_pipeline.fit(X_train, y_train)

# --- Flask API ---

app = Flask(__name__)

@app.route('/predict_spam', methods=['POST'])
def predict_spam():
    if not request.is_json:
        return jsonify({"error": "Request must be JSON"}), 400

    data = request.get_json()
    email_text = data.get('email_text')

    if not email_text:
        return jsonify({"error": "Missing 'email_text' in request body"}), 400

    # Predict probability
    # model_pipeline.predict_proba returns probabilities for [class 0, class 1]
    # We want the probability of being spam (class 1)
    spam_probability = model_pipeline.predict_proba([email_text])[0][1]

    return jsonify({
        "email_text": email_text,
        "spam_probability": spam_probability
    })

if __name__ == '__main__':
    # For production, use a production-ready WSGI server like Gunicorn or uWSGI
    app.run(debug=True, host='0.0.0.0', port=5000)